"use client";

import { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { useRouter } from "next/navigation";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import {
    Siren, Flame, Heart, Shield, Wrench, HelpCircle, User, DoorOpen, MapPin, AlertTriangle, ArrowRight, ArrowLeft, Loader2, CheckCircle2, Zap
} from "lucide-react";
import Link from "next/link";
import { AiTriageResult } from "@/types/database";

const crisisTypes = [
    { value: "fire", label: "Fire / Smoke", icon: Flame },
    { value: "medical", label: "Medical Emergency", icon: Heart },
    { value: "security", label: "Security Threat", icon: Shield },
    { value: "maintenance", label: "Hazard/Spill", icon: Wrench },
    { value: "other", label: "Other", icon: HelpCircle },
];

const severityLevels = [
    { value: "low", label: "LOW: Not urgent but needs attention", color: "#22C55E" },
    { value: "medium", label: "MEDIUM: Concerning situation", color: "#EAB308" },
    { value: "high", label: "HIGH: Potentially dangerous", color: "#F97316" },
    { value: "critical", label: "CRITICAL: Immediate life danger", color: "#EF4444" },
];

export default function ReportCrisisPage() {
    const [step, setStep] = useState(1);
    const [, setLoading] = useState(false);
    const [error, setError] = useState("");
    const [triage, setTriage] = useState<AiTriageResult | null>(null);
    const [, setCrisisId] = useState("");

    const [form, setForm] = useState({
        guest_name: "",
        room_number: "",
        crisis_type: "",
        description: "",
        location_description: "",
        severity_assessment: "medium",
    });

    const handleSubmit = async () => {
        setLoading(true);
        setError("");
        setStep(4); // AI Processing state

        try {
            const res = await fetch("/api/crisis/report", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(form),
            });
            const data = await res.json();
            if (!res.ok) throw new Error(data.error || "Failed to submit report");

            setTriage(data.triage);
            setCrisisId(data.crisis_id);
            setStep(5); // Success state
        } catch (err: unknown) {
            setError(err instanceof Error ? err.message : "Something went wrong.");
            setStep(3); // Revert to final form step on error
        } finally {
            setLoading(false);
        }
    };

    const nextStep = () => setStep(s => Math.min(3, s + 1));
    const prevStep = () => setStep(s => Math.max(1, s - 1));

    return (
        <div className="min-h-screen bg-[#0A0A0A] text-[#FFFFFF] font-sans selection:bg-[#3B82F6]/30 flex flex-col">
            {/* Minimal Header */}
            <header className="border-b border-[#1F1F1F] bg-[#0A0A0A]/80 backdrop-blur-md">
                <div className="max-w-3xl mx-auto px-6 h-16 flex items-center justify-between">
                    <Link href="/" className="flex items-center gap-2">
                        <Siren className="w-4 h-4 text-[#EF4444]" />
                        <span className="font-semibold text-sm">CrisisSync Report</span>
                    </Link>
                    {step <= 3 && (
                        <div className="flex gap-1.5 items-center">
                            {[1, 2, 3].map(i => (
                                <div key={i} className={`w-12 h-1 rounded-sm transition-colors ${i <= step ? 'bg-[#3B82F6]' : 'bg-[#1F1F1F]'}`} />
                            ))}
                        </div>
                    )}
                </div>
            </header>

            {/* Main Content Area */}
            <main className="flex-grow flex items-center justify-center p-6 pb-24 relative overflow-hidden">

                {/* Error Banner */}
                <AnimatePresence>
                    {error && (
                        <motion.div 
                            initial={{ y: -50, opacity: 0 }}
                            animate={{ y: 0, opacity: 1 }}
                            exit={{ y: -50, opacity: 0 }}
                            className="absolute top-6 left-1/2 -translate-x-1/2 px-4 py-3 border border-[#EF4444]/50 bg-[#EF4444]/10 rounded shadow-lg flex items-center gap-3 z-50 min-w-[300px]"
                        >
                            <AlertTriangle className="w-4 h-4 text-[#EF4444]" />
                            <span className="text-sm font-medium">{error}</span>
                        </motion.div>
                    )}
                </AnimatePresence>

                <div className="w-full max-w-lg relative">
                    <AnimatePresence mode="popLayout">
                        {step === 1 && (
                            <motion.div
                                key="step1"
                                initial={{ opacity: 0, x: 20 }}
                                animate={{ opacity: 1, x: 0 }}
                                exit={{ opacity: 0, x: -20 }}
                                transition={{ duration: 0.3 }}
                                className="space-y-6"
                            >
                                <div>
                                    <h1 className="text-2xl font-bold tracking-tight mb-2">Who are you?</h1>
                                    <p className="text-sm text-[#A1A1AA]">Provide your details so staff can locate and identify you.</p>
                                </div>
                                <div className="space-y-4">
                                    <div className="space-y-2">
                                        <label className="text-xs font-semibold uppercase tracking-wide text-[#A1A1AA] flex items-center gap-2">
                                            <User className="w-3.5 h-3.5" /> Full Name
                                        </label>
                                        <Input
                                            value={form.guest_name}
                                            onChange={(e) => setForm({ ...form, guest_name: e.target.value })}
                                            className="bg-[#111111] border-[#1F1F1F] focus-visible:ring-[#3B82F6] h-12"
                                            placeholder="e.g. Jane Doe"
                                        />
                                    </div>
                                    <div className="space-y-2">
                                        <label className="text-xs font-semibold uppercase tracking-wide text-[#A1A1AA] flex items-center gap-2">
                                            <DoorOpen className="w-3.5 h-3.5" /> Room / Unit Number
                                        </label>
                                        <Input
                                            value={form.room_number}
                                            onChange={(e) => setForm({ ...form, room_number: e.target.value })}
                                            className="bg-[#111111] border-[#1F1F1F] focus-visible:ring-[#3B82F6] h-12"
                                            placeholder="e.g. 402"
                                        />
                                    </div>
                                </div>
                                <Button 
                                    onClick={nextStep} 
                                    disabled={!form.guest_name || !form.room_number} 
                                    className="w-full h-12 bg-[#FFFFFF] text-[#0A0A0A] hover:bg-[#E5E5E5] font-semibold mt-4"
                                >
                                    Continue <ArrowRight className="w-4 h-4 ml-2" />
                                </Button>
                            </motion.div>
                        )}

                        {step === 2 && (
                            <motion.div
                                key="step2"
                                initial={{ opacity: 0, x: 20 }}
                                animate={{ opacity: 1, x: 0 }}
                                exit={{ opacity: 0, x: -20 }}
                                transition={{ duration: 0.3 }}
                                className="space-y-6"
                            >
                                <div>
                                    <h1 className="text-2xl font-bold tracking-tight mb-2">What is happening?</h1>
                                    <p className="text-sm text-[#A1A1AA]">Select the emergency type and provide details.</p>
                                </div>
                                <div className="grid grid-cols-2 lg:grid-cols-3 gap-3">
                                    {crisisTypes.map((type) => (
                                        <button
                                            key={type.value}
                                            onClick={() => setForm({ ...form, crisis_type: type.value })}
                                            className={`p-4 border rounded flex flex-col justify-center items-center gap-3 transition-colors ${form.crisis_type === type.value ? "bg-[#3B82F6]/10 border-[#3B82F6] text-[#3B82F6]" : "bg-[#111111] border-[#1F1F1F] text-[#A1A1AA] hover:border-[#3B82F6]/50"}`}
                                        >
                                            <type.icon className="w-6 h-6" />
                                            <span className="text-xs font-semibold text-center leading-tight">{type.label}</span>
                                        </button>
                                    ))}
                                </div>

                                <div className="space-y-2 mt-4">
                                    <label className="text-xs font-semibold uppercase tracking-wide text-[#A1A1AA] flex items-center gap-2">
                                        <MapPin className="w-3.5 h-3.5" /> Specific Location
                                    </label>
                                    <Input
                                        value={form.location_description}
                                        onChange={(e) => setForm({ ...form, location_description: e.target.value })}
                                        className="bg-[#111111] border-[#1F1F1F] h-12"
                                        placeholder="e.g. 4th floor hallway near elevator"
                                    />
                                </div>

                                <div className="space-y-2">
                                    <label className="text-xs font-semibold uppercase tracking-wide text-[#A1A1AA]">
                                        Details (What do you see?)
                                    </label>
                                    <Textarea
                                        value={form.description}
                                        onChange={(e) => setForm({ ...form, description: e.target.value })}
                                        className="bg-[#111111] border-[#1F1F1F] resize-none h-24"
                                        placeholder="Describe the situation..."
                                    />
                                </div>

                                <div className="flex gap-3 pt-2">
                                    <Button onClick={prevStep} variant="outline" className="h-12 border-[#1F1F1F] bg-transparent text-[#A1A1AA] hover:text-[#FFF] hover:bg-[#111111] px-4">
                                        <ArrowLeft className="w-4 h-4" />
                                    </Button>
                                    <Button 
                                        onClick={nextStep} 
                                        disabled={!form.crisis_type || !form.description} 
                                        className="flex-1 h-12 bg-[#FFFFFF] text-[#0A0A0A] hover:bg-[#E5E5E5] font-semibold"
                                    >
                                        Continue <ArrowRight className="w-4 h-4 ml-2" />
                                    </Button>
                                </div>
                            </motion.div>
                        )}

                        {step === 3 && (
                            <motion.div
                                key="step3"
                                initial={{ opacity: 0, x: 20 }}
                                animate={{ opacity: 1, x: 0 }}
                                exit={{ opacity: 0, x: -20 }}
                                transition={{ duration: 0.3 }}
                                className="space-y-6"
                            >
                                <div>
                                    <h1 className="text-2xl font-bold tracking-tight mb-2">Assess Severity</h1>
                                    <p className="text-sm text-[#A1A1AA]">How dangerous is the current situation?</p>
                                </div>

                                <div className="space-y-3">
                                    {severityLevels.map((lvl) => {
                                        const isSelected = form.severity_assessment === lvl.value;
                                        return (
                                            <button
                                                key={lvl.value}
                                                onClick={() => setForm({ ...form, severity_assessment: lvl.value })}
                                                className={`w-full p-4 border rounded flex items-center gap-4 transition-all ${isSelected ? 'border-current bg-current/10' : 'bg-[#111111] border-[#1F1F1F] hover:border-[#1F1F1F] hover:bg-[#1A1A1A]'}`}
                                                style={{ color: isSelected ? lvl.color : '#A1A1AA' }}
                                            >
                                                <div className={`w-3 h-3 rounded-full`} style={{ backgroundColor: isSelected ? lvl.color : '#A1A1AA' }} />
                                                <span className={`text-sm font-semibold tracking-wide ${isSelected ? 'text-white' : ''}`}>
                                                    {lvl.label}
                                                </span>
                                            </button>
                                        );
                                    })}
                                </div>

                                <div className="p-4 rounded border border-[#1F1F1F] bg-[#111111] mt-6">
                                    <h4 className="text-xs font-bold uppercase tracking-wider text-[#A1A1AA] mb-2 flex items-center gap-2">
                                        <Siren className="w-3.5 h-3.5" /> Before Submitting
                                    </h4>
                                    <p className="text-sm text-[#A1A1AA] leading-relaxed">
                                        By clicking submit, this report will instantly alert all on-duty staff. Please verify the accuracy of the location: <strong className="text-white">{form.location_description || form.room_number}</strong>.
                                    </p>
                                </div>

                                <div className="flex gap-3 pt-2">
                                    <Button onClick={prevStep} variant="outline" className="h-12 border-[#1F1F1F] bg-transparent text-[#A1A1AA] hover:text-[#FFF] hover:bg-[#111111] px-4">
                                        <ArrowLeft className="w-4 h-4" />
                                    </Button>
                                    <Button 
                                        onClick={handleSubmit} 
                                        className="flex-1 h-12 bg-[#EF4444] hover:bg-[#DC2626] text-white font-bold"
                                        style={{ boxShadow: '0 0 20px rgba(239, 68, 68, 0.3)' }}
                                    >
                                        Transmit Emergency Alert
                                    </Button>
                                </div>
                            </motion.div>
                        )}

                        {step === 4 && (
                            <motion.div
                                key="step4"
                                initial={{ opacity: 0, scale: 0.95 }}
                                animate={{ opacity: 1, scale: 1 }}
                                className="flex flex-col items-center justify-center py-20 text-center space-y-8"
                            >
                                <div className="relative">
                                    <div className="absolute inset-0 rounded-full bg-[#3B82F6]/20 blur-xl animate-pulse" />
                                    <div className="w-20 h-20 border border-[#3B82F6]/50 rounded-full bg-[#0A0A0A] flex items-center justify-center relative z-10">
                                        <Loader2 className="w-8 h-8 text-[#3B82F6] animate-spin" />
                                    </div>
                                </div>
                                <div>
                                    <h2 className="text-xl font-bold mb-2">Analyzing with Gemini AI</h2>
                                    <p className="text-sm text-[#A1A1AA] max-w-xs mx-auto">
                                        Generating safety instructions and routing this crisis to the nearest available staff team.
                                    </p>
                                </div>
                                <div className="font-mono text-xs text-[#3B82F6]/70 mt-4 h-6">
                                    [ TRANSMITTING PAYLOAD SECURELY ]
                                </div>
                            </motion.div>
                        )}

                        {step === 5 && triage && (
                            <motion.div
                                key="step5"
                                initial={{ opacity: 0, y: 30 }}
                                animate={{ opacity: 1, y: 0 }}
                                className="space-y-8 text-center"
                            >
                                <div className="flex flex-col items-center">
                                    <div className="w-16 h-16 rounded-full bg-[#22C55E]/20 border border-[#22C55E] flex items-center justify-center mb-6">
                                        <CheckCircle2 className="w-8 h-8 text-[#22C55E]" />
                                    </div>
                                    <h1 className="text-3xl font-bold tracking-tighter mb-2">Alert Received</h1>
                                    <p className="text-sm text-[#A1A1AA]">Staff have been notified and are responding immediately.</p>
                                </div>

                                <div className="text-left border border-[#3B82F6] bg-[#3B82F6]/5 rounded-lg p-6 relative overflow-hidden">
                                    <div className="absolute top-0 right-0 p-3 opacity-20"><Zap className="w-12 h-12" /></div>
                                    <h3 className="text-xs font-mono font-bold text-[#3B82F6] uppercase tracking-wider mb-4 border-b border-[#3B82F6]/20 pb-2">
                                        AI Safety Instructions
                                    </h3>
                                    <ul className="space-y-4">
                                        {triage.guest_instructions.map((inst, i) => (
                                            <li key={i} className="flex gap-3 text-sm">
                                                <div className="w-1.5 h-1.5 rounded-full bg-[#3B82F6] shrink-0 mt-1.5" />
                                                <span className="text-[#FFFFFF] leading-relaxed">{inst}</span>
                                            </li>
                                        ))}
                                    </ul>
                                </div>

                                <Link href="/" className="block">
                                    <Button variant="outline" className="w-full h-12 border-[#1F1F1F] bg-transparent text-[#FFFFFF] hover:bg-[#111111]">
                                        Return Home
                                    </Button>
                                </Link>
                            </motion.div>
                        )}
                    </AnimatePresence>
                </div>
            </main>
        </div>
    );
}
